const input = $input.first().json;

const sessionId = input.sessionId || input.chatId || 'chat-' + Date.now();
const messageText = input.chatInput || input.message || input.text || '';

return [{
  json: {
    userId: sessionId,
    userName: 'Chat User',
    messageText,
    mediaUrl: null,
    mediaType: 'text',
    channel: 'chat',
    sessionId,
    rawPayload: input
  }
}];

const entry = $input.first().json;
const value = entry.entry?.[0]?.changes?.[0]?.value || {};
const contacts = value.contacts || [];
const messages = value.messages || [];

if (!messages.length) return [];

const msg = messages[0];
const contact = contacts[0] || {};

let mediaUrl = null;
let mediaType = 'text';
let messageText = null;

if (msg.type === 'text') {
  messageText = msg.text?.body || '';
} else if (msg.type === 'image') {
  mediaType = 'image';
  mediaUrl = msg.image?.id || null;
  messageText = msg.image?.caption || '';
} else if (msg.type === 'document') {
  mediaType = 'pdf';
  mediaUrl = msg.document?.id || null;
  messageText = msg.document?.caption || '';
}

return [{
  json: {
    userId: contact.wa_id || msg.from || '',
    userName: contact.profile?.name || '',
    messageText,
    mediaUrl,
    mediaType,
    channel: 'whatsapp',
    rawPayload: entry
  }
}];

const update = $input.first().json;
const msg = update.message || {};
const chat = msg.chat || {};
const from = msg.from || {};

let mediaUrl = null;
let mediaType = 'text';
let messageText = msg.text || '';

if (msg.photo && msg.photo.length > 0) {
  mediaType = 'image';
  mediaUrl = msg.photo[msg.photo.length - 1].file_id;
  messageText = msg.caption || '';
} else if (msg.document) {
  const mime = msg.document.mime_type || '';
  mediaType = mime.includes('pdf') ? 'pdf' : 'image';
  mediaUrl = msg.document.file_id;
  messageText = msg.caption || '';
}

return [{
  json: {
    userId: String(chat.id || ''),
    userName: [from.first_name, from.last_name].filter(Boolean).join(' '),
    messageText,
    mediaUrl,
    mediaType,
    channel: 'telegram',
    rawPayload: update
  }
}];

const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    userId: body.userId || body.user_id || '',
    userName: body.userName || body.user_name || '',
    messageText: body.text || body.message || '',
    mediaUrl: body.mediaUrl || body.media_url || null,
    mediaType: body.mediaType || body.media_type || 'text',
    channel: 'webhook',
    rawPayload: body
  }
}];

const input = $input.first().json;
const lookupResults = $('Lookup User Profile').all() || [];
const normalized = $('Normalize Telegram').all().concat(
  // $('Normalize WhatsApp').all(),
  // $('Normalize Webhook').all()
);
const msg = normalized.find(n => n.json.userId || n.json.id || n.json.profileId || n.json.chatId || n.json.phone) || { json: {} };

console.log('lookupResults:', JSON.stringify(lookupResults, null, 2));
console.log('normalized:', JSON.stringify(normalized, null, 2));
console.log('msg:', JSON.stringify(msg, null, 2));

function getId(item) {
  if (!item || !item.json) return undefined;
  const candidates = [
    item.json.userId,
    item.json.user_id,
    item.json.id,
    item.json.profileId,
    item.json.profile_id,
    item.json.telegramId,
    item.json.chatId,
    item.json.phone,
    item.json.from,
    (item.json.payload && item.json.payload.userId)
  ];
  for (const c of candidates) {
    if (c !== undefined && c !== null && c !== '') return String(c).trim();
  }
  return undefined;
}

const msgId = getId(msg);
console.log('msgId:', msgId);

const userRow = lookupResults.find(r => {
  const rid = getId(r);
  return rid && msgId && rid === msgId;
});

console.log('userRow:', JSON.stringify(userRow, null, 2));

if (!userRow) {
  return [{ json: { ...msg.json, isNew: true, isAwaiting: false, profileData: null } }];
}

if (userRow.json.state === 'awaitingProfileName') {
  return [{ json: { ...msg.json, isNew: false, isAwaiting: true, profileData: userRow.json } }];
}

return [{ json: { ...msg.json, isNew: false, isAwaiting: false, profileData: userRow.json } }];

const msg = $input.first().json;
return [{
  json: {
    ...msg,
    replyText: '👋 Welcome! I\'m your expense tracker bot. What name would you like for your profile?',
    action: 'askProfileName',
    state: 'awaitingProfileName'
  }
}];

const spreadsheetId = $input.first().json.spreadsheetId;
const profileName = $('Route User State').first().json.messageText;
const categories = [
  'Makanan & Minuman', 'Transportasi', 'Tagihan', 'Hiburan',
  'Belanja', 'Kesehatan', 'Langganan', 'Lain-lain'
];

return categories.map(cat => ({
  json: {
    spreadsheetId,
    profileName,
    Category: cat,
    Budget: 0,
    'Spent This Month': 0,
    Remaining: 0
  }
}));

const msg = $('Route User State').first().json;
const profileName = msg.messageText;
return [{
  json: {
    ...msg,
    replyText: `✅ Profile "${profileName}" created! Your expense tracker spreadsheet is ready.\n\nYou can now:\n• Send expenses: "Lunch 45k"\n• Check budget: "Check my budget"\n• Get reports: "Monthly report"\n• Set budget: "Set food budget 500k"\n\nSend any expense to get started!`,
    action: 'registrationComplete'
  }
}];

const input = $input.first().json;
const binary = $input.first().binary;

return [{
  json: {
    ...input,
    messageText: (input.messageText || '') + '\n[Attached: ' + input.mediaType + ' file - please extract all expense items from this receipt/document]',
    hasMedia: true,
    mediaProcessed: true
  },
  binary
}];

// Get AI node output (prefer first item)
const aiAll = $('AI Agent (Groq)').all() || [];
const aiItem = aiAll.length ? aiAll[0].json : (($('AI Agent (Groq)').first() || {}).json || {});
const originalData = ($('Merge User Context').first() || {}).json || {};

function tryParseJsonString(s) {
  if (typeof s !== 'string') return null;
  const match = s.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
  const toTry = match ? match[0] : s;
  try {
    return JSON.parse(toTry);
  } catch (e) {
    return null;
  }
}

function extractIntentFromText(s) {
  if (!s || typeof s !== 'string') return null;
  // common patterns: "intent":"value"  or intent: value  or intent = value
  let m = s.match(/"intent"\s*[:=]\s*"([^"]+)"/i) || s.match(/intent\s*[:=]\s*["']?([a-zA-Z0-9_-]+)["']?/i);
  return m ? m[1].trim() : null;
}

// Find the candidate content from different possible fields
let candidate = aiItem.output ?? aiItem.result ?? aiItem.response ?? aiItem.text ?? aiItem;

// If candidate is an object and contains an `output` field deeper
if (candidate && typeof candidate === 'object' && Object.keys(candidate).length === 0 && aiItem) {
  candidate = aiItem;
}

let parsed = null;

// If candidate is string -> try parse JSON, else fallback to heuristics
if (typeof candidate === 'string') {
  parsed = tryParseJsonString(candidate);
  if (!parsed) {
    // fallback: try to detect intent and plain text reply
    parsed = {
      intent: extractIntentFromText(candidate) || undefined,
      replyText: candidate.trim(),
      raw: candidate,
    };
  }
} else if (Array.isArray(candidate)) {
  // if array, take first element that looks like object, or merge
  const firstObj = candidate.find(el => typeof el === 'object' && el !== null);
  parsed = firstObj ? (firstObj.output ?? firstObj) : { replyText: String(candidate) };
} else if (typeof candidate === 'object' && candidate !== null) {
  // object: accept as-is or unwrap nested 'output'
  parsed = candidate.output && typeof candidate.output !== 'object' ? tryParseJsonString(candidate.output) ?? candidate.output : (candidate.output ?? candidate);
}

// Final safety: ensure parsed is an object
if (!parsed || typeof parsed !== 'object') {
  parsed = { intent: 'help', replyText: parsed ? String(parsed) : '', error: 'Could not parse AI response' };
}

// Derive intent and replyText robustly from multiple shapes
const parsedIntent =
  parsed.intent ||
  parsed.action ||
  parsed.command ||
  (parsed.result && (parsed.result.intent || parsed.result.action)) ||
  extractIntentFromText(parsed.replyText) ||
  'help';

const replyText =
  parsed.replyText ||
  parsed.text ||
  parsed.response ||
  (typeof parsed === 'string' ? parsed : '') ||
  '';

// Return merged result for downstream routing
return [
  {
    json: {
      ...originalData,
      ...parsed,
      parsedIntent,
      replyText,
      _ai_raw: aiItem,
    },
  },
];

const response = $input.first().json;
const sheets = (response.sheets || []).map(s => s.properties.title);
const now = new Date();
const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const monthSheet = monthNames[now.getMonth()] + '-' + now.getFullYear();
const originalData = $('Route by Intent').first().json;

return [{
  json: {
    ...originalData,
    monthSheet,
    sheetExists: sheets.includes(monthSheet),
    spreadsheetId: originalData.spreadsheetId
  }
}];

const data = $input.first().json;
return [{
  json: {
    ...data,
    replyText: data.replyText || `✅ Recorded: ${data.description} ${data.currency || 'IDR'} ${Number(data.amount).toLocaleString()} (${data.category})`
  }
}];

const rows = $input.all().map(i => i.json);
const originalData = $('Route by Intent').first().json;
const category = originalData.category;

let lines = ['📊 Budget Status:\n'];
const filtered = category ? rows.filter(r => r.Category === category) : rows;

for (const row of filtered) {
  const budget = Number(row.Budget) || 0;
  const spent = Number(row['Spent This Month']) || 0;
  const remaining = budget - spent;
  const status = budget > 0 ? (remaining >= 0 ? '✅' : '⚠️') : '—';
  lines.push(`${status} ${row.Category}: Spent ${spent.toLocaleString()} / Budget ${budget.toLocaleString()} (Remaining: ${remaining.toLocaleString()})`);
}

return [{
  json: {
    ...originalData,
    replyText: lines.join('\n')
  }
}];

const data = $input.first().json;
const originalData = $('Route by Intent').first().json;
return [{
  json: {
    ...originalData,
    replyText: `✅ Budget set: ${originalData.category} = ${originalData.currency || 'IDR'} ${Number(originalData.amount).toLocaleString()} per ${originalData.period || 'month'}`
  }
}];

const rows = $input.all().map(i => i.json);
const originalData = $('Route by Intent').first().json;

const byCategory = {};
let total = 0;

for (const row of rows) {
  const cat = row.Category || 'Lain-lain';
  const amt = Number(row.Amount) || 0;
  byCategory[cat] = (byCategory[cat] || 0) + amt;
  total += amt;
}

let lines = [`📊 Expense Report (${originalData.period || 'This Month'}):\n`];
const sorted = Object.entries(byCategory).sort((a, b) => b[1] - a[1]);

for (const [cat, amt] of sorted) {
  const pct = total > 0 ? ((amt / total) * 100).toFixed(1) : 0;
  lines.push(`• ${cat}: IDR ${amt.toLocaleString()} (${pct}%)`);
}

lines.push(`\n💰 Total: IDR ${total.toLocaleString()}`);
lines.push(`📝 Transactions: ${rows.length}`);

return [{
  json: {
    ...originalData,
    replyText: lines.join('\n')
  }
}];

const data = $input.first().json;
const splitWith = data.splitWith;
const totalAmount = Number(data.amount);
const shareAmount = Math.round(totalAmount / 2);

return [{
  json: {
    ...data,
    selfAmount: shareAmount,
    otherAmount: totalAmount - shareAmount,
    otherProfile: splitWith,
    replyText: `✅ Split recorded: ${data.description} IDR ${totalAmount.toLocaleString()}\n• Your share: IDR ${shareAmount.toLocaleString()}\n• ${splitWith}'s share: IDR ${(totalAmount - shareAmount).toLocaleString()}`
  }
}];

const data = $input.first().json;
const targetRows = $('Lookup Split Target Profile').all();
const target = targetRows.find(r => r.json.profileName === data.otherProfile);

if (!target) {
  return [{
    json: {
      ...data,
      replyText: `⚠️ Profile "${data.otherProfile}" not found. They need to register first.`
    }
  }];
}

return [{
  json: {
    ...data,
    targetSpreadsheetId: target.json.spreadsheetId,
    amount: data.selfAmount
  }
}];

const data = $input.first().json;
return [{
  json: {
    output: data.replyText || 'Sorry, something went wrong.',
    sessionId: data.sessionId || data.userId
  }
}];

const msg = $input.first().json;
return [{
  json: {
    ...msg,
    replyText: 'Saving your profile name...',
    action: 'savingProfileName',
    state: 'savingProfileName'
  }
}];
